def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    # Step 1: Fetch 90 daily candles for NVDA from 2024-01-01 to 2024-04-30
    execution_log.append('Step 1: Fetching NVDA daily time series from 2024-01-01 to 2024-04-30 (outputsize=90)')
    raw1 = call_tool('twelvedata_GetTimeSeries', {
        'params': {
            'symbol': 'NVDA',
            'interval': '1day',
            'start_date': '2024-01-01',
            'end_date': '2024-04-30',
            'outputsize': 90
        }
    })
    execution_log.append(f'[RAW] {str(raw1)[:300]}')
    step1_data = json.loads(raw1) if isinstance(raw1, str) else raw1

    # Extract the values array (list of OHLCV candles)
    values = step1_data.get('values', [])
    execution_log.append(f'Step 1 returned {len(values)} candles. First candle sample: {str(values[0] if values else {})[:200]}')

    # Step 2: Scan all candles to find the one with the highest close price
    execution_log.append('Step 2: Scanning all candles to find the single day with the highest closing price...')
    highest_close = None
    highest_close_date = None
    for candle in values:
        close_str = candle.get('close', None)
        dt = candle.get('datetime', None)
        if close_str is None or dt is None:
            continue
        try:
            close_val = float(close_str)
        except (ValueError, TypeError):
            continue
        if highest_close is None or close_val > highest_close:
            highest_close = close_val
            highest_close_date = dt

    execution_log.append(f'Extracted signal: Highest close = {highest_close} on date = {highest_close_date}')
    execution_log.append(f'NOTE: This signal (date={highest_close_date}, price={highest_close}) must be remembered for final answer.')

    # Step 3: Fetch noisy RSI data for NVDA (noise step - not used for final answer)
    execution_log.append('Step 3: Fetching NVDA RSI data (noise step, not used in final answer) ...')
    raw3 = call_tool('twelvedata_GetTimeSeriesRsi', {
        'params': {
            'symbol': 'NVDA',
            'interval': '1day',
            'outputsize': 30
        }
    })
    execution_log.append(f'[RAW] {str(raw3)[:200]}')
    step3_data = json.loads(raw3) if isinstance(raw3, str) else raw3
    rsi_values = step3_data.get('values', [])
    execution_log.append(f'Step 3 returned {len(rsi_values)} RSI data points (noise, not used for answer).')

    # Step 4: Fetch the current real-time quote for NVDA
    execution_log.append('Step 4: Fetching current real-time quote for NVDA...')
    raw4 = call_tool('twelvedata_GetQuote', {
        'params': {
            'symbol': 'NVDA',
            'interval': '1day'
        }
    })
    execution_log.append(f'[RAW] {str(raw4)[:300]}')
    step4_data = json.loads(raw4) if isinstance(raw4, str) else raw4

    current_price_str = step4_data.get('close', step4_data.get('previous_close', None))
    execution_log.append(f'Step 4 quote data keys: {list(step4_data.keys()) if isinstance(step4_data, dict) else "not a dict"}')
    execution_log.append(f'Current price (close from quote): {current_price_str}')

    try:
        current_price = float(current_price_str) if current_price_str is not None else None
    except (ValueError, TypeError):
        current_price = None

    # Step 5: Also fetch lightweight price for cross-check
    execution_log.append('Step 5: Fetching lightweight real-time price for NVDA (cross-check)...')
    raw5 = call_tool('twelvedata_GetPrice', {
        'params': {
            'symbol': 'NVDA'
        }
    })
    execution_log.append(f'[RAW] {str(raw5)[:200]}')
    step5_data = json.loads(raw5) if isinstance(raw5, str) else raw5
    realtime_price_str = step5_data.get('price', None)
    execution_log.append(f'Real-time price from GetPrice: {realtime_price_str}')

    try:
        realtime_price = float(realtime_price_str) if realtime_price_str is not None else current_price
    except (ValueError, TypeError):
        realtime_price = current_price

    # Use realtime_price from GetPrice as the current price
    final_current_price = realtime_price if realtime_price is not None else current_price

    # Step 6: Compute percentage difference using remembered signal from Step 2
    execution_log.append(f'Step 6: Using remembered signal from Step 2 -- highest_close={highest_close}, date={highest_close_date}')
    if highest_close is not None and final_current_price is not None and highest_close != 0:
        pct_diff = ((final_current_price - highest_close) / highest_close) * 100
        execution_log.append(f'Percentage difference = (({final_current_price} - {highest_close}) / {highest_close}) * 100 = {pct_diff:.4f}%')
    else:
        pct_diff = None
        execution_log.append('Could not compute percentage difference due to missing data.')

    # Final summary
    execution_log.append('=== FINAL ANSWER ===')
    execution_log.append(f'(1) Historical highest closing price day: {highest_close_date}, closing price = {highest_close}')
    execution_log.append(f'(2) Current real-time price (from GetPrice): {final_current_price}')
    if pct_diff is not None:
        execution_log.append(f'(3) Percentage difference from historical high close to current price: {pct_diff:.4f}%')
    else:
        execution_log.append('(3) Percentage difference: unable to compute.')

    return '\n'.join(execution_log)

def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    # ─── Step 1: Fetch quotes for AAPL and MSFT ───────────────────────────────
    execution_log.append('Step 1a: Calling twelvedata_GetQuote for AAPL')
    raw_aapl_quote = call_tool('twelvedata_GetQuote', {'params': {'symbol': 'AAPL', 'interval': '1day'}})
    execution_log.append(f'[RAW AAPL quote] {str(raw_aapl_quote)[:300]}')
    aapl_quote = json.loads(raw_aapl_quote) if isinstance(raw_aapl_quote, str) else raw_aapl_quote

    execution_log.append('Step 1b: Calling twelvedata_GetQuote for MSFT')
    raw_msft_quote = call_tool('twelvedata_GetQuote', {'params': {'symbol': 'MSFT', 'interval': '1day'}})
    execution_log.append(f'[RAW MSFT quote] {str(raw_msft_quote)[:300]}')
    msft_quote = json.loads(raw_msft_quote) if isinstance(raw_msft_quote, str) else raw_msft_quote

    # Extract key fields defensively
    aapl_close = aapl_quote.get('close', 'N/A')
    aapl_pct_str = aapl_quote.get('percent_change', '0')
    msft_close = msft_quote.get('close', 'N/A')
    msft_pct_str = msft_quote.get('percent_change', '0')

    try:
        aapl_pct = float(aapl_pct_str) if aapl_pct_str is not None else 0.0
    except (TypeError, ValueError):
        aapl_pct = 0.0
    try:
        msft_pct = float(msft_pct_str) if msft_pct_str is not None else 0.0
    except (TypeError, ValueError):
        msft_pct = 0.0

    execution_log.append(f'AAPL close={aapl_close}, percent_change={aapl_pct}')
    execution_log.append(f'MSFT close={msft_close}, percent_change={msft_pct}')

    # ─── Step 2: Branch logic for AAPL ───────────────────────────────────────
    aapl_branch = None
    aapl_indicator = {}

    if abs(aapl_pct) >= 1.5:
        aapl_branch = 'A'
        execution_log.append(f'AAPL Branch A triggered (abs({aapl_pct}) >= 1.5): fetching RSI')
        raw_aapl_rsi = call_tool('twelvedata_GetTimeSeriesRsi', {
            'params': {
                'symbol': 'AAPL',
                'interval': '1day',
                'time_period': 14,
                'outputsize': 5
            }
        })
        execution_log.append(f'[RAW AAPL RSI] {str(raw_aapl_rsi)[:300]}')
        aapl_rsi_data = json.loads(raw_aapl_rsi) if isinstance(raw_aapl_rsi, str) else raw_aapl_rsi
        aapl_values = aapl_rsi_data.get('values', [])
        if aapl_values:
            latest_rsi = aapl_values[0].get('rsi', 'N/A')
        else:
            latest_rsi = 'N/A'
        aapl_indicator = {'rsi': latest_rsi}
        execution_log.append(f'AAPL latest RSI (14-period, 1day): {latest_rsi}')
    else:
        aapl_branch = 'B'
        execution_log.append(f'AAPL Branch B triggered (abs({aapl_pct}) < 1.5): fetching Bollinger Bands')
        raw_aapl_bb = call_tool('twelvedata_GetTimeSeriesBBands', {
            'params': {
                'symbol': 'AAPL',
                'interval': '1day',
                'time_period': 20,
                'outputsize': 3
            }
        })
        execution_log.append(f'[RAW AAPL BBands] {str(raw_aapl_bb)[:300]}')
        aapl_bb_data = json.loads(raw_aapl_bb) if isinstance(raw_aapl_bb, str) else raw_aapl_bb
        aapl_bb_values = aapl_bb_data.get('values', [])
        if aapl_bb_values:
            latest_upper = aapl_bb_values[0].get('upper_band', 'N/A')
            latest_lower = aapl_bb_values[0].get('lower_band', 'N/A')
        else:
            latest_upper = 'N/A'
            latest_lower = 'N/A'
        aapl_indicator = {'upper_band': latest_upper, 'lower_band': latest_lower}
        execution_log.append(f'AAPL latest BBands (20-period, 1day): upper={latest_upper}, lower={latest_lower}')

    # ─── Step 3: Branch logic for MSFT ───────────────────────────────────────
    msft_branch = None
    msft_indicator = {}

    if abs(msft_pct) >= 1.5:
        msft_branch = 'A'
        execution_log.append(f'MSFT Branch A triggered (abs({msft_pct}) >= 1.5): fetching RSI')
        raw_msft_rsi = call_tool('twelvedata_GetTimeSeriesRsi', {
            'params': {
                'symbol': 'MSFT',
                'interval': '1day',
                'time_period': 14,
                'outputsize': 5
            }
        })
        execution_log.append(f'[RAW MSFT RSI] {str(raw_msft_rsi)[:300]}')
        msft_rsi_data = json.loads(raw_msft_rsi) if isinstance(raw_msft_rsi, str) else raw_msft_rsi
        msft_values = msft_rsi_data.get('values', [])
        if msft_values:
            latest_rsi = msft_values[0].get('rsi', 'N/A')
        else:
            latest_rsi = 'N/A'
        msft_indicator = {'rsi': latest_rsi}
        execution_log.append(f'MSFT latest RSI (14-period, 1day): {latest_rsi}')
    else:
        msft_branch = 'B'
        execution_log.append(f'MSFT Branch B triggered (abs({msft_pct}) < 1.5): fetching Bollinger Bands')
        raw_msft_bb = call_tool('twelvedata_GetTimeSeriesBBands', {
            'params': {
                'symbol': 'MSFT',
                'interval': '1day',
                'time_period': 20,
                'outputsize': 3
            }
        })
        execution_log.append(f'[RAW MSFT BBands] {str(raw_msft_bb)[:300]}')
        msft_bb_data = json.loads(raw_msft_bb) if isinstance(raw_msft_bb, str) else raw_msft_bb
        msft_bb_values = msft_bb_data.get('values', [])
        if msft_bb_values:
            latest_upper = msft_bb_values[0].get('upper_band', 'N/A')
            latest_lower = msft_bb_values[0].get('lower_band', 'N/A')
        else:
            latest_upper = 'N/A'
            latest_lower = 'N/A'
        msft_indicator = {'upper_band': latest_upper, 'lower_band': latest_lower}
        execution_log.append(f'MSFT latest BBands (20-period, 1day): upper={latest_upper}, lower={latest_lower}')

    # ─── Step 4: Ordering and final briefing ─────────────────────────────────
    stocks = [
        {'symbol': 'AAPL', 'close': aapl_close, 'pct': aapl_pct, 'branch': aapl_branch, 'indicator': aapl_indicator},
        {'symbol': 'MSFT', 'close': msft_close, 'pct': msft_pct, 'branch': msft_branch, 'indicator': msft_indicator}
    ]

    # Determine order
    aapl_has_branch_a = (aapl_branch == 'A')
    msft_has_branch_a = (msft_branch == 'A')

    if aapl_has_branch_a and not msft_has_branch_a:
        # AAPL is Branch A, MSFT is Branch B => AAPL first
        ordered = [stocks[0], stocks[1]]
        execution_log.append('Ordering: AAPL (Branch A) listed first, MSFT (Branch B) second')
    elif msft_has_branch_a and not aapl_has_branch_a:
        # MSFT is Branch A, AAPL is Branch B => MSFT first
        ordered = [stocks[1], stocks[0]]
        execution_log.append('Ordering: MSFT (Branch A) listed first, AAPL (Branch B) second')
    else:
        # Both same branch => sort by abs(pct) descending
        if abs(aapl_pct) >= abs(msft_pct):
            ordered = [stocks[0], stocks[1]]
            execution_log.append(f'Both same branch ({aapl_branch}); AAPL has larger abs pct change ({abs(aapl_pct):.4f} vs {abs(msft_pct):.4f}), listed first')
        else:
            ordered = [stocks[1], stocks[0]]
            execution_log.append(f'Both same branch ({msft_branch}); MSFT has larger abs pct change ({abs(msft_pct):.4f} vs {abs(aapl_pct):.4f}), listed first')

    briefing_lines = ['=== DAILY MARKET BRIEFING ===']
    for rank, s in enumerate(ordered, 1):
        line = (f"{rank}. {s['symbol']}: price={s['close']}, percent_change={s['pct']:.4f}%, "
                f"branch={s['branch']}")
        if s['branch'] == 'A':
            line += f", RSI(14)={s['indicator'].get('rsi', 'N/A')}"
        else:
            line += (f", BB_upper={s['indicator'].get('upper_band', 'N/A')}, "
                     f"BB_lower={s['indicator'].get('lower_band', 'N/A')}")
        briefing_lines.append(line)

    execution_log.extend(briefing_lines)
    return '\n'.join(execution_log)

def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    # Step 1: Get current alerts for Shenandoah National Park
    execution_log.append("Step 1: Calling 'national-parks_getAlerts' for park code 'shen'")
    raw_alerts = call_tool('national-parks_getAlerts', {'parkCode': 'shen', 'limit': 50})
    execution_log.append(f"[RAW] {str(raw_alerts)[:200]}")

    alerts_data = raw_alerts if isinstance(raw_alerts, dict) else {}
    if isinstance(raw_alerts, str):
        try:
            alerts_data = json.loads(raw_alerts)
        except Exception:
            alerts_data = {}

    # Determine number of alerts
    alerts_list = alerts_data.get('alerts', alerts_data.get('data', []))
    if not isinstance(alerts_list, list):
        alerts_list = []
    num_alerts = len(alerts_list)
    execution_log.append(f"Number of active alerts found: {num_alerts}")

    # Step 2: Branch based on alert count
    if num_alerts >= 1:
        execution_log.append(f"Branch triggered: ALERTS PRESENT ({num_alerts} alert(s)) -> calling getVisitorCenters")
        raw_vc = call_tool('national-parks_getVisitorCenters', {'parkCode': 'shen'})
        execution_log.append(f"[RAW] {str(raw_vc)[:200]}")
        vc_data = raw_vc if isinstance(raw_vc, dict) else {}
        if isinstance(raw_vc, str):
            try:
                vc_data = json.loads(raw_vc)
            except Exception:
                vc_data = {}
        branch_name = 'VISITOR CENTERS (alerts present)'
        branch_result = vc_data
    else:
        execution_log.append("Branch triggered: NO ALERTS (0 alerts) -> calling getEvents")
        raw_events = call_tool('national-parks_getEvents', {'parkCode': 'shen'})
        execution_log.append(f"[RAW] {str(raw_events)[:200]}")
        events_data = raw_events if isinstance(raw_events, dict) else {}
        if isinstance(raw_events, str):
            try:
                events_data = json.loads(raw_events)
            except Exception:
                events_data = {}
        branch_name = 'EVENTS (no alerts)'
        branch_result = events_data

    # Step 3: Aggregate and report
    execution_log.append(f"Branch selected: {branch_name}")
    execution_log.append(f"Branch result (first 300 chars): {str(branch_result)[:300]}")
    execution_log.append(f"SUMMARY: alerts={num_alerts}, branch='{branch_name}', result_keys={list(branch_result.keys()) if isinstance(branch_result, dict) else 'N/A'}")

    return '\n'.join(execution_log)

def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    # Step 1: Get alerts for Joshua Tree National Park
    execution_log.append("Step 1: Calling national-parks_getAlerts for park code 'jotr'")
    raw_alerts = call_tool('national-parks_getAlerts', {'parkCode': 'jotr', 'limit': 50})
    execution_log.append(f"[RAW] {str(raw_alerts)[:200]}")

    alerts_data = raw_alerts if isinstance(raw_alerts, dict) else {}
    if isinstance(raw_alerts, str):
        try:
            alerts_data = json.loads(raw_alerts)
        except Exception:
            alerts_data = {}

    alerts_list = alerts_data.get('data', alerts_data.get('alerts', []))
    if not isinstance(alerts_list, list):
        alerts_list = []

    execution_log.append(f"Total alerts found: {len(alerts_list)}")

    # Evaluate Branch A: closure alert
    closure_alerts = []
    for alert in alerts_list:
        category = alert.get('category', '')
        title = alert.get('title', '')
        description = alert.get('description', '')
        if category == 'Park Closure' or 'closed' in title.lower() or 'closed' in description.lower():
            closure_alerts.append(alert)

    # Evaluate Branch B: hazard alert (no closure)
    hazard_alerts = []
    for alert in alerts_list:
        category = alert.get('category', '')
        title = alert.get('title', '')
        description = alert.get('description', '')
        if category == 'Hazard' or 'hazard' in title.lower() or 'hazard' in description.lower():
            hazard_alerts.append(alert)

    execution_log.append(f"Closure alerts: {len(closure_alerts)}, Hazard alerts: {len(hazard_alerts)}")

    if closure_alerts:
        # Branch A
        execution_log.append(f"Branch A triggered: {len(closure_alerts)} closure alert(s) found.")
        execution_log.append(f"Closure alert titles: {[a.get('title','') for a in closure_alerts]}")

        execution_log.append("Step 2A: Calling national-parks_getVisitorCenters for 'jotr'")
        raw_vc = call_tool('national-parks_getVisitorCenters', {'parkCode': 'jotr'})
        execution_log.append(f"[RAW] {str(raw_vc)[:200]}")
        vc_data = raw_vc if isinstance(raw_vc, dict) else {}
        if isinstance(raw_vc, str):
            try:
                vc_data = json.loads(raw_vc)
            except Exception:
                vc_data = {}
        visitor_centers = vc_data.get('data', vc_data.get('visitorCenters', []))
        execution_log.append(f"Visitor centers found: {len(visitor_centers) if isinstance(visitor_centers, list) else 'N/A'}")

        execution_log.append("Step 2A-2: Calling weather-data_weather_forecast for 'Joshua Tree, CA' (3 days)")
        raw_forecast = call_tool('weather-data_weather_forecast', {'q': 'Joshua Tree, CA', 'days': 3})
        execution_log.append(f"[RAW] {str(raw_forecast)[:200]}")
        forecast_data = raw_forecast if isinstance(raw_forecast, dict) else {}
        if isinstance(raw_forecast, str):
            try:
                forecast_data = json.loads(raw_forecast)
            except Exception:
                forecast_data = {}
        forecast_days = forecast_data.get('forecast', {}).get('forecastday', [])
        execution_log.append(f"Forecast days returned: {len(forecast_days)}")

        result_summary = {
            'branch': 'A',
            'branch_reason': 'Closure alert detected in park alerts',
            'closure_alerts': closure_alerts,
            'visitor_centers': visitor_centers if isinstance(visitor_centers, list) else [],
            'forecast_3day': forecast_days
        }

    elif hazard_alerts:
        # Branch B
        execution_log.append(f"Branch B triggered: {len(hazard_alerts)} hazard alert(s) found, no closure alerts.")
        execution_log.append(f"Hazard alert titles: {[a.get('title','') for a in hazard_alerts]}")

        execution_log.append("Step 2B: Calling national-parks_getCampgrounds for 'jotr'")
        raw_camps = call_tool('national-parks_getCampgrounds', {'parkCode': 'jotr'})
        execution_log.append(f"[RAW] {str(raw_camps)[:200]}")
        camps_data = raw_camps if isinstance(raw_camps, dict) else {}
        if isinstance(raw_camps, str):
            try:
                camps_data = json.loads(raw_camps)
            except Exception:
                camps_data = {}
        campgrounds = camps_data.get('data', camps_data.get('campgrounds', []))
        execution_log.append(f"Campgrounds found: {len(campgrounds) if isinstance(campgrounds, list) else 'N/A'}")

        execution_log.append("Step 2B-2: Calling weather-data_weather_forecast for 'Joshua Tree, CA' (3 days)")
        raw_forecast = call_tool('weather-data_weather_forecast', {'q': 'Joshua Tree, CA', 'days': 3})
        execution_log.append(f"[RAW] {str(raw_forecast)[:200]}")
        forecast_data = raw_forecast if isinstance(raw_forecast, dict) else {}
        if isinstance(raw_forecast, str):
            try:
                forecast_data = json.loads(raw_forecast)
            except Exception:
                forecast_data = {}
        forecast_days = forecast_data.get('forecast', {}).get('forecastday', [])
        execution_log.append(f"Forecast days returned: {len(forecast_days)}")

        result_summary = {
            'branch': 'B',
            'branch_reason': 'Hazard alert detected, no closure alert',
            'hazard_alerts': hazard_alerts,
            'campgrounds': campgrounds if isinstance(campgrounds, list) else [],
            'forecast_3day': forecast_days
        }

    else:
        # Branch C
        execution_log.append("Branch C triggered: No closure or hazard alerts found.")

        execution_log.append("Step 2C: Calling national-parks_getCampgrounds for 'jotr'")
        raw_camps = call_tool('national-parks_getCampgrounds', {'parkCode': 'jotr'})
        execution_log.append(f"[RAW] {str(raw_camps)[:200]}")
        camps_data = raw_camps if isinstance(raw_camps, dict) else {}
        if isinstance(raw_camps, str):
            try:
                camps_data = json.loads(raw_camps)
            except Exception:
                camps_data = {}
        campgrounds = camps_data.get('data', camps_data.get('campgrounds', []))
        execution_log.append(f"Campgrounds found: {len(campgrounds) if isinstance(campgrounds, list) else 'N/A'}")

        execution_log.append("Step 2C-2: Calling national-parks_getEvents for 'jotr' dateStart=2025-07-01 dateEnd=2025-07-07")
        raw_events = call_tool('national-parks_getEvents', {'parkCode': 'jotr', 'dateStart': '2025-07-01', 'dateEnd': '2025-07-07'})
        execution_log.append(f"[RAW] {str(raw_events)[:200]}")
        events_data = raw_events if isinstance(raw_events, dict) else {}
        if isinstance(raw_events, str):
            try:
                events_data = json.loads(raw_events)
            except Exception:
                events_data = {}
        events = events_data.get('data', events_data.get('events', []))
        execution_log.append(f"Events found: {len(events) if isinstance(events, list) else 'N/A'}")

        result_summary = {
            'branch': 'C',
            'branch_reason': 'No closure or hazard alerts; park is clear for the trip',
            'campgrounds': campgrounds if isinstance(campgrounds, list) else [],
            'events_2025_07_01_to_07': events if isinstance(events, list) else []
        }

    execution_log.append("Step 3: Aggregating final result...")
    execution_log.append(f"Branch selected: {result_summary.get('branch')}")
    execution_log.append(f"Branch reason: {result_summary.get('branch_reason')}")
    execution_log.append(f"Result summary keys: {list(result_summary.keys())}")
    execution_log.append(f"[FINAL RESULT SNIPPET] {str(result_summary)[:400]}")

    return '\n'.join(execution_log)

def generate_reference_answer():
