def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    # STEP 1: Get latest quote for NVDA
    execution_log.append("Step 1: Calling tool 'twelvedata_GetQuote' for NVDA")
    raw_quote = call_tool('twelvedata_GetQuote', {'params': {'symbol': 'NVDA', 'interval': '1day'}})
    execution_log.append(f"[RAW] {str(raw_quote)[:200]}")
    quote_data = json.loads(raw_quote) if isinstance(raw_quote, str) else raw_quote

    pct_change_str = quote_data.get('percent_change', None)
    close_str = quote_data.get('close', None)
    quote_datetime = quote_data.get('datetime', None)

    try:
        pct_change = float(pct_change_str) if pct_change_str is not None else None
    except (ValueError, TypeError):
        pct_change = None
    try:
        latest_close = float(close_str) if close_str is not None else None
    except (ValueError, TypeError):
        latest_close = None

    execution_log.append(f"NVDA percent_change = {pct_change}, close = {latest_close}, datetime = {quote_datetime}")

    if pct_change is None:
        execution_log.append("ERROR: percent_change unavailable, cannot branch.")
        return "\n".join(execution_log)

    result = {'top_branch': None, 'sub_case': None, 'indicators': {}, 'verdict': None, 'percent_change': pct_change}

    # BRANCH A: percent_change >= 2.0
    if pct_change >= 2.0:
        execution_log.append(f"Branch A triggered: percent_change={pct_change} >= 2.0")
        result['top_branch'] = 'A'

        execution_log.append("Step A1: Calling tool 'twelvedata_GetTimeSeriesRsi'")
        raw_rsi = call_tool('twelvedata_GetTimeSeriesRsi', {'params': {'symbol': 'NVDA', 'interval': '1day', 'time_period': 14, 'outputsize': 5}})
        execution_log.append(f"[RAW] {str(raw_rsi)[:200]}")
        rsi_data = json.loads(raw_rsi) if isinstance(raw_rsi, str) else raw_rsi
        rsi_values = rsi_data.get('values', []) or []
        latest_rsi_item = rsi_values[0] if rsi_values else {}
        latest_rsi_str = latest_rsi_item.get('rsi', None)
        try:
            latest_rsi = float(latest_rsi_str) if latest_rsi_str is not None else None
        except (ValueError, TypeError):
            latest_rsi = None
        result['indicators']['rsi'] = {'value': latest_rsi, 'datetime': latest_rsi_item.get('datetime')}
        execution_log.append(f"Latest RSI = {latest_rsi}")

        if latest_rsi is not None and latest_rsi > 70:
            execution_log.append("Sub-case: OVERBOUGHT_VOLATILITY_CHECK (RSI > 70)")
            result['sub_case'] = 'OVERBOUGHT_VOLATILITY_CHECK'
            raw_atr = call_tool('twelvedata_GetTimeSeriesAtr', {'params': {'symbol': 'NVDA', 'interval': '1day', 'time_period': 14, 'outputsize': 5}})
            execution_log.append(f"[RAW] {str(raw_atr)[:200]}")
            atr_data = json.loads(raw_atr) if isinstance(raw_atr, str) else raw_atr
            atr_values = atr_data.get('values', []) or []
            latest_atr_item = atr_values[0] if atr_values else {}
            result['indicators']['atr'] = {'value': latest_atr_item.get('atr'), 'datetime': latest_atr_item.get('datetime')}
            result['verdict'] = 'OVERBOUGHT'
        else:
            execution_log.append("Sub-case: TREND_CONFIRM (RSI <= 70)")
            result['sub_case'] = 'TREND_CONFIRM'
            raw_ema = call_tool('twelvedata_GetTimeSeriesEma', {'params': {'symbol': 'NVDA', 'interval': '1day', 'time_period': 9, 'outputsize': 5}})
            execution_log.append(f"[RAW] {str(raw_ema)[:200]}")
            ema_data = json.loads(raw_ema) if isinstance(raw_ema, str) else raw_ema
            ema_values = ema_data.get('values', []) or []
            latest_ema_item = ema_values[0] if ema_values else {}
            result['indicators']['ema'] = {'value': latest_ema_item.get('ema'), 'datetime': latest_ema_item.get('datetime')}
            result['verdict'] = 'TREND_CONFIRMED'

    # BRANCH B: -2.0 < percent_change < 2.0
    elif pct_change > -2.0 and pct_change < 2.0:
        execution_log.append(f"Branch B triggered: -2.0 < percent_change={pct_change} < 2.0")
        result['top_branch'] = 'B'

        execution_log.append("Step B1: Calling tool 'twelvedata_GetTimeSeriesMacd'")
        raw_macd = call_tool('twelvedata_GetTimeSeriesMacd', {'params': {'symbol': 'NVDA', 'interval': '1day', 'fast_period': 12, 'slow_period': 26, 'signal_period': 9, 'outputsize': 5}})
        execution_log.append(f"[RAW] {str(raw_macd)[:200]}")
        macd_data = json.loads(raw_macd) if isinstance(raw_macd, str) else raw_macd
        macd_values = macd_data.get('values', []) or []
        latest_macd_item = macd_values[0] if macd_values else {}
        macd_str = latest_macd_item.get('macd')
        signal_str = latest_macd_item.get('macd_signal')
        try:
            macd_v = float(macd_str) if macd_str is not None else None
            signal_v = float(signal_str) if signal_str is not None else None
        except (ValueError, TypeError):
            macd_v, signal_v = None, None
        result['indicators']['macd'] = {'macd': macd_v, 'macd_signal': signal_v, 'datetime': latest_macd_item.get('datetime')}
        if macd_v is not None and signal_v is not None:
            if macd_v > signal_v:
                result['verdict'] = 'BULLISH_CROSSOVER'
                execution_log.append(f"MACD bullish: {macd_v} > {signal_v}")
            else:
                result['verdict'] = 'BEARISH_CROSSOVER'
                execution_log.append(f"MACD bearish: {macd_v} <= {signal_v}")
        else:
            result['verdict'] = 'BEARISH_CROSSOVER'

    # BRANCH C: percent_change <= -2.0
    else:
        execution_log.append(f"Branch C triggered: percent_change={pct_change} <= -2.0")
        result['top_branch'] = 'C'

        execution_log.append("Step C1: Calling tool 'twelvedata_GetTimeSeriesBBands'")
        raw_bb = call_tool('twelvedata_GetTimeSeriesBBands', {'params': {'symbol': 'NVDA', 'interval': '1day', 'time_period': 20, 'sd': 2, 'outputsize': 5}})
        execution_log.append(f"[RAW] {str(raw_bb)[:200]}")
        bb_data = json.loads(raw_bb) if isinstance(raw_bb, str) else raw_bb
        bb_values = bb_data.get('values', []) or []
        latest_bb_item = bb_values[0] if bb_values else {}
        lower_band_str = latest_bb_item.get('lower_band')
        try:
            lower_band = float(lower_band_str) if lower_band_str is not None else None
        except (ValueError, TypeError):
            lower_band = None
        result['indicators']['bbands'] = {'lower_band': lower_band, 'middle_band': latest_bb_item.get('middle_band'), 'upper_band': latest_bb_item.get('upper_band'), 'datetime': latest_bb_item.get('datetime')}
        execution_log.append(f"Latest close={latest_close}, lower_band={lower_band}")

        if latest_close is not None and lower_band is not None and latest_close < lower_band:
            execution_log.append("Sub-case: OVERSOLD_TREND_STRENGTH (close below lower band)")
            result['sub_case'] = 'OVERSOLD_TREND_STRENGTH'
            raw_adx = call_tool('twelvedata_GetTimeSeriesAdx', {'params': {'symbol': 'NVDA', 'interval': '1day', 'time_period': 14, 'outputsize': 5}})
            execution_log.append(f"[RAW] {str(raw_adx)[:200]}")
            adx_data = json.loads(raw_adx) if isinstance(raw_adx, str) else raw_adx
            adx_values = adx_data.get('values', []) or []
            latest_adx_item = adx_values[0] if adx_values else {}
            result['indicators']['adx'] = {'value': latest_adx_item.get('adx'), 'datetime': latest_adx_item.get('datetime')}
            result['verdict'] = 'OVERSOLD_BREAKDOWN'
        else:
            execution_log.append("Sub-case: OVERSOLD_NO_BREAK (close still inside lower band)")
            result['sub_case'] = 'OVERSOLD_NO_BREAK'
            result['verdict'] = 'OVERSOLD_HOLDING'

    execution_log.append(f"Final aggregated result: {str(result)[:500]}")
    return "\n".join(execution_log)
